#pragma once\\\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\n// Correctly expose function under 'baseline' naming; avoid extraneous braces per registry\\\\\nnamespace baseline {\n    void matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\n        // Loop unrolled over output slot columns (for cache) and inner loop over values\\\\\n        for (size_t i = 0; i < M; ++i) {\\\\\n            for (size_t j = 0; j < K; j += 16) {\\\\\n                float sum[16] = {0.0f};\n                    // For every B column chunk, accumulate per output slot\\n                for (size_t k = 0; k < K; ++k) {\\\\\n                    uint32_t b = B[k * (K/32) + j/32];\n                    bool bitSign = (b >> (j % 32)) & 1u;\n                    float sign = bitSign ? 1.0f : -1.0f;\n                    sum[k % 16] += A[i * K + k] * sign;\\\n                }\\\n                // Final write back\\n                for (size_t k = 0; k < 16; ++k) {\\\\\n                    size_t idx = j + k;\n                    if (idx < K)\ C[i * K + idx] = sum[k];\\\\n                }\\\n            }\\\n        }\\\n    }\n}\n